export const savePaperToDB = async (paper: QuestionPaper): Promise<void> => {
  const existingIndex = papersStore.findIndex(p => p.id === paper.id);
  if (existingIndex >= 0) {
    papersStore[existingIndex] = paper;
  } else {
    papersStore.push(paper);
  }
  await new Promise(r => setTimeout(r, 500));
};

export const getPapersForAdmin = async (): Promise<QuestionPaper[]> => {
  await new Promise(r => setTimeout(r, 500));
  return papersStore.filter(p => p.status === PaperStatus.PENDING_APPROVAL);
};

export const updatePaperStatus = async (id: string, status: PaperStatus, feedback?: string): Promise<void> => {
  const paper = papersStore.find(p => p.id === id);
  if (paper) {
    paper.status = status;
    paper.adminFeedback = feedback;
  }
  await new Promise(r => setTimeout(r, 400));
};

