import React, { useState } from 'react';
import { generateQuestionsFromPrompt, analyzeCurriculum } from '../services/geminiService';
import { savePaperToDB } from '../services/mockServices';
import { Question, QuestionPaper, PaperStatus, QuestionType, Difficulty } from '../types';

const FacultyDashboard: React.FC<{ userId: string; userName: string }> = ({ userId, userName }) => {
  const [activeTab, setActiveTab] = useState<'prompt' | 'upload' | 'curriculum'>('prompt');
  const [prompt, setPrompt] = useState('');
  const [generatedQuestions, setGeneratedQuestions] = useState<Question[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [paperTitle, setPaperTitle] = useState('');
  const [isSaved, setIsSaved] = useState(false);

  // --- Handlers ---

  const handlePromptGenerate = async () => {
    if (!prompt) return;
    setIsLoading(true);
    try {
      const questions = await generateQuestionsFromPrompt(prompt, 5, Difficulty.MEDIUM);
      setGeneratedQuestions(prev => [...prev, ...questions]);
    } catch (e) {
      alert("Error generating questions");
    } finally {
      setIsLoading(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, type: 'paper' | 'curriculum') => {
    if (e.target.files && e.target.files[0]) {
      setIsLoading(true);
      // Simulation of OCR / File processing
      setTimeout(async () => {
        if (type === 'curriculum') {
             const topics = await analyzeCurriculum("Mock curriculum text");
             const questions = await generateQuestionsFromPrompt(`Questions based on: ${topics.join(', ')}`, 5);
             setGeneratedQuestions(prev => [...prev, ...questions]);
        } else {
             // Mock extraction from old paper
             const mockExtracted: Question = {
                 id: `ocr-${Date.now()}`,
                 text: "Extracted: What is the time complexity of QuickSort?",
                 type: QuestionType.MCQ,
                 difficulty: Difficulty.MEDIUM,
                 options: ["O(n)", "O(n log n)", "O(n^2)", "O(1)"],
                 correctAnswer: "O(n log n)",
                 marks: 1
             };
             setGeneratedQuestions(prev => [...prev, mockExtracted]);
        }
        setIsLoading(false);
      }, 1500);
    }
  };

  const handleRemoveQuestion = (id: string) => {
    setGeneratedQuestions(prev => prev.filter(q => q.id !== id));
  };

  const handleSaveForApproval = async () => {
    if (!paperTitle || generatedQuestions.length === 0) {
        alert("Please add a title and at least one question.");
        return;
    }
    setIsLoading(true);
    const paper: QuestionPaper = {
        id: `paper-${Date.now()}`,
        title: paperTitle,
        courseCode: "CS-TEMP",
        facultyId: userId,
        facultyName: userName,
        createdAt: new Date().toISOString(),
        status: PaperStatus.PENDING_APPROVAL,
        questions: generatedQuestions,
        totalMarks: generatedQuestions.reduce((acc, q) => acc + q.marks, 0),
        durationMinutes: 90
    };

    await savePaperToDB(paper);
    setIsLoading(false);
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
    setGeneratedQuestions([]);
    setPaperTitle("");
  };

  const handleExport = () => {
     // Simulation of PDF export
     alert("Downloading PDF with college template...");
  };

  // --- UI Components ---

  return (
    <div className="max-w-5xl mx-auto space-y-8">
      <div>
        <h2 className="text-3xl font-bold text-gray-900">Create Question Paper</h2>
        <p className="text-gray-500">Use AI to generate, upload old papers, or analyze curriculum.</p>
      </div>

      {/* Creation Mode Tabs */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="flex border-b border-gray-200 bg-gray-50">
          <button 
            onClick={() => setActiveTab('prompt')}
            className={`flex-1 py-4 text-sm font-medium ${activeTab === 'prompt' ? 'bg-white text-indigo-600 border-t-2 border-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
          >
            ✨ AI Prompt
          </button>
          <button 
            onClick={() => setActiveTab('upload')}
            className={`flex-1 py-4 text-sm font-medium ${activeTab === 'upload' ? 'bg-white text-indigo-600 border-t-2 border-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
          >
            📄 Previous Paper (OCR)
          </button>
          <button 
            onClick={() => setActiveTab('curriculum')}
            className={`flex-1 py-4 text-sm font-medium ${activeTab === 'curriculum' ? 'bg-white text-indigo-600 border-t-2 border-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
          >
            📚 Curriculum
          </button>
        </div>

        <div className="p-6">
            {activeTab === 'prompt' && (
                <div className="space-y-4">
                    <label className="block text-sm font-medium text-gray-700">Enter Instructions</label>
                    <textarea 
                        className="w-full border border-gray-300 rounded-lg p-3 focus:ring-2 focus:ring-indigo-500 outline-none"
                        rows={4}
                        placeholder="e.g. Create 10 MCQs on Data Structures focusing on Graphs, medium difficulty."
                        value={prompt}
                        onChange={(e) => setPrompt(e.target.value)}
                    />
                    <div className="flex justify-end">
                        <button 
                            onClick={handlePromptGenerate}
                            disabled={isLoading || !prompt}
                            className="bg-indigo-600 text-white px-6 py-2 rounded-lg hover:bg-indigo-700 disabled:opacity-50 transition"
                        >
                            {isLoading ? 'Generating...' : 'Generate Questions'}
                        </button>
                    </div>
                </div>
            )}

            {activeTab === 'upload' && (
                <div className="border-2 border-dashed border-gray-300 rounded-lg p-8 text-center hover:bg-gray-50 transition">
                    <div className="mx-auto h-12 w-12 text-gray-400 mb-3">📄</div>
                    <p className="text-sm text-gray-600 mb-4">Upload a PDF or DOCX of a previous exam.</p>
                    <input type="file" accept=".pdf,.docx" onChange={(e) => handleFileUpload(e, 'paper')} className="block w-full text-sm text-slate-500
                      file:mr-4 file:py-2 file:px-4
                      file:rounded-full file:border-0
                      file:text-sm file:font-semibold
                      file:bg-indigo-50 file:text-indigo-700
                      hover:file:bg-indigo-100
                    "/>
                </div>
            )}

            {activeTab === 'curriculum' && (
                <div className="border-2 border-dashed border-gray-300 rounded-lg p-8 text-center hover:bg-gray-50 transition">
                    <div className="mx-auto h-12 w-12 text-gray-400 mb-3">📚</div>
                    <p className="text-sm text-gray-600 mb-4">Upload Curriculum Syllabus to generate a topic-wise bank.</p>
                     <input type="file" accept=".pdf,.docx" onChange={(e) => handleFileUpload(e, 'curriculum')} className="block w-full text-sm text-slate-500
                      file:mr-4 file:py-2 file:px-4
                      file:rounded-full file:border-0
                      file:text-sm file:font-semibold
                      file:bg-indigo-50 file:text-indigo-700
                      hover:file:bg-indigo-100
                    "/>
                </div>
            )}
        </div>
      </div>

      {/* Paper Builder Area */}
      {generatedQuestions.length > 0 && (
          <div className="space-y-6 animate-fade-in">
              <div className="flex justify-between items-end">
                  <div className="flex-1 mr-4">
                      <label className="block text-sm font-medium text-gray-700 mb-1">Paper Title</label>
                      <input 
                        type="text" 
                        value={paperTitle} 
                        onChange={(e) => setPaperTitle(e.target.value)}
                        placeholder="e.g. End Semester Examination - Fall 2024"
                        className="w-full border-b-2 border-gray-300 focus:border-indigo-600 outline-none px-2 py-1 text-lg font-semibold bg-transparent"
                      />
                  </div>
                  <div className="text-right">
                       <p className="text-sm text-gray-500">Total Marks</p>
                       <p className="text-2xl font-bold text-indigo-600">{generatedQuestions.reduce((a, b) => a + b.marks, 0)}</p>
                  </div>
              </div>

              <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 space-y-6">
                 {generatedQuestions.map((q, idx) => (
                     <div key={q.id} className="group relative border rounded-lg p-4 hover:border-indigo-300 transition-colors">
                         <div className="flex justify-between items-start mb-2">
                             <span className="bg-indigo-100 text-indigo-800 text-xs font-semibold px-2 py-1 rounded">Q{idx + 1} • {q.type} • {q.marks} Marks</span>
                             <button onClick={() => handleRemoveQuestion(q.id)} className="text-red-400 hover:text-red-600">
                                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
                             </button>
                         </div>
                         <p className="font-medium text-gray-800 mb-3">{q.text}</p>
                         {q.options && q.options.length > 0 && (
                             <ul className="grid grid-cols-2 gap-2">
                                 {q.options.map((opt, i) => (
                                     <li key={i} className="text-sm text-gray-600 bg-gray-50 p-2 rounded border border-gray-100">{String.fromCharCode(65 + i)}. {opt}</li>
                                 ))}
                             </ul>
                         )}
                         <div className="mt-3 text-xs text-green-600 font-medium">
                            Answer: {q.correctAnswer}
                         </div>
                     </div>
                 ))}
              </div>

              <div className="flex justify-between items-center bg-gray-50 p-4 rounded-lg">
                  <button onClick={handleExport} className="text-indigo-600 font-medium hover:text-indigo-800 flex items-center">
                      ⬇ Download Preview (PDF)
                  </button>

                  <div className="flex space-x-3">
                     <button className="px-4 py-2 border border-gray-300 text-gray-700 rounded-lg bg-white hover:bg-gray-50">Save Draft</button>
                     <button 
                        onClick={handleSaveForApproval}
                        disabled={isLoading}
                        className="px-6 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 shadow-sm"
                     >
                         {isLoading ? 'Submitting...' : 'Submit for Approval'}
                     </button>
                  </div>
              </div>
          </div>
      )}

      {isSaved && (
        <div className="fixed bottom-8 right-8 bg-green-600 text-white px-6 py-3 rounded-lg shadow-lg flex items-center animate-bounce">
            ✅ Submitted for approval successfully!
        </div>
      )}
    </div>
  );
};

