import React, { useEffect, useState } from 'react';
import { getPapersForAdmin, updatePaperStatus } from '../services/mockServices';
import { QuestionPaper, PaperStatus } from '../types';

const AdminDashboard: React.FC = () => {
  const [papers, setPapers] = useState<QuestionPaper[]>([]);
  const [selectedPaper, setSelectedPaper] = useState<QuestionPaper | null>(null);
  const [feedback, setFeedback] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadQueue();
  }, []);

  const loadQueue = async () => {
    setLoading(true);
    const data = await getPapersForAdmin();
    setPapers(data);
    setLoading(false);
  };

  const handleDecision = async (status: PaperStatus) => {
    if (!selectedPaper) return;
    await updatePaperStatus(selectedPaper.id, status, feedback);
    setSelectedPaper(null);
    setFeedback('');
    loadQueue();
  };

  if (selectedPaper) {
    return (
      <div className="bg-white rounded-xl shadow-xl border border-gray-200 overflow-hidden max-w-4xl mx-auto">
        <div className="p-6 border-b border-gray-200 flex justify-between items-center bg-gray-50">
          <div>
            <h2 className="text-xl font-bold text-gray-800">{selectedPaper.title}</h2>
            <p className="text-sm text-gray-500">Created by {selectedPaper.facultyName} • {selectedPaper.courseCode}</p>
          </div>
          <button onClick={() => setSelectedPaper(null)} className="text-gray-500 hover:text-gray-800">Close</button>
        </div>

        <div className="p-8 max-h-[60vh] overflow-y-auto">
          {selectedPaper.questions.map((q, i) => (
            <div key={q.id} className="mb-6 pb-6 border-b border-gray-100 last:border-0">
               <div className="flex items-baseline mb-2">
                   <span className="font-bold mr-2 text-indigo-600">Q{i + 1}.</span>
                   <p className="text-gray-800 font-medium">{q.text}</p>
                   <span className="ml-auto text-xs font-semibold bg-gray-100 px-2 py-1 rounded">[{q.marks} Marks]</span>
               </div>
               {q.options && q.options.length > 0 && (
                   <div className="ml-6 grid grid-cols-2 gap-2 mt-2">
                       {q.options.map((opt, idx) => (
                           <div key={idx} className="text-sm text-gray-600 bg-gray-50 p-2 rounded">{String.fromCharCode(65+idx)}. {opt}</div>
                       ))}
                   </div>
               )}
            </div>
          ))}
        </div>

        <div className="p-6 bg-gray-50 border-t border-gray-200">
           <label className="block text-sm font-medium text-gray-700 mb-2">Feedback / Rejection Reason</label>
           <textarea 
             className="w-full p-3 border border-gray-300 rounded-lg mb-4"
             placeholder="Optional feedback..."
             value={feedback}
             onChange={(e) => setFeedback(e.target.value)}
           />
           <div className="flex justify-end space-x-3">
             <button 
                onClick={() => handleDecision(PaperStatus.REJECTED)}
                className="px-6 py-2 border border-red-300 text-red-700 rounded-lg hover:bg-red-50"
             >
                Reject
             </button>
             <button 
                onClick={() => handleDecision(PaperStatus.APPROVED)}
                className="px-6 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700"
             >
                Approve & Finalize
             </button>
           </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto">
      <h2 className="text-2xl font-bold mb-6">Review Queue</h2>
      {loading ? (
        <div className="text-center py-10 text-gray-500">Loading queue...</div>
      ) : papers.length === 0 ? (
        <div className="bg-white p-10 rounded-xl shadow-sm text-center">
            <div className="text-4xl mb-4">🎉</div>
            <p className="text-gray-500">All caught up! No pending papers to review.</p>
        </div>
      ) : (
        <div className="grid gap-4">
          {papers.map(paper => (
            <div key={paper.id} className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 flex justify-between items-center hover:shadow-md transition">
              <div>
                <h3 className="font-bold text-lg text-gray-900">{paper.title}</h3>
                <p className="text-sm text-gray-500">
                   {paper.courseCode} • {paper.facultyName} • {paper.questions.length} Questions
                </p>
                <span className="inline-block mt-2 text-xs font-semibold text-yellow-800 bg-yellow-100 px-2 py-1 rounded-full">
                  Pending Approval
                </span>
              </div>
              <button 
                onClick={() => setSelectedPaper(paper)}
                className="bg-indigo-50 text-indigo-700 px-5 py-2 rounded-lg font-medium hover:bg-indigo-100"
              >
                Review
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

