                  <button className="bg-indigo-600 text-white px-6 py-2 rounded-lg hover:bg-indigo-700">Select File</button>
              </div>
          </div>
      )
  }

  return (
    <div className="max-w-5xl mx-auto space-y-8">
      <div>
        <h2 className="text-3xl font-bold text-gray-900">Create Question Paper</h2>
        <p className="text-gray-500">Use AI to generate, upload old papers, or analyze curriculum.</p>
      </div>

      {/* Creation Mode Tabs */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
