// --- Mailgun Service ---
export const sendWelcomeEmail = async (user: User) => {
  const MAILGUN_DOMAIN = process.env.MAILGUN_DOMAIN || "sandbox-your-domain.mailgun.org";
  const MAILGUN_API_KEY = process.env.MAILGUN_API_KEY || "";

  const emailContent = `Welcome to Q-Genius, ${user.firstName}!

  We're thrilled to have you.
  Log in now: https://q-genius.app

  Regards,
  The Q-Genius Team`;

  console.log(`[EMAIL SERVICE] Sending welcome email to ${user.email} via Mailgun...`);

  if (!MAILGUN_API_KEY) {
      console.warn("Mailgun API Key missing. Email logged to console only.");
      return;
  }

  try {
    const formData = new FormData();
    formData.append("from", `Q-Genius <mailgun@${MAILGUN_DOMAIN}>`);
    formData.append("to", user.email);
    formData.append("subject", `Welcome to Q-Genius, ${user.firstName}!`);
