// --- Auth Services ---

export const signUpUser = async (email: string, password: string, userData: Partial<User>) => {
    // 1. Create Auth User
    const { data: authData, error: authError } = await supabase.auth.signUp({
        email,
        password,
        options: {
            data: {
                first_name: userData.firstName,
                last_name: userData.lastName,
                role: userData.role,
                department: userData.department
            }
        }
    });

    if (authError) throw authError;
    if (!authData.user) throw new Error("No user created");

    const newUser: User = {
        uid: authData.user.id,
        email: email,
        firstName: userData.firstName!,
        lastName: userData.lastName!,
        role: userData.role || UserRole.FACULTY,
        department: userData.department
    };

    // 2. Create Profile Entry (If not handled by DB triggers)
    const { error: profileError } = await supabase.from('profiles').insert({
        uid: newUser.uid,
        email: newUser.email,
        first_name: newUser.firstName,
        last_name: newUser.lastName,
        role: newUser.role,
        department: newUser.department
    });

    if (profileError) {
        console.error("Profile creation failed:", profileError);
        // Continue anyway as auth succeeded
    }

    return newUser;
};

export const loginUser = async (email: string, password: string): Promise<User> => {
    const { data, error } = await supabase.auth.signInWithPassword({
        email,
        password
    });

    if (error) throw error;
    if (!data.user) throw new Error("Login failed");

    // Fetch profile details
    const { data: profile, error: profileError } = await supabase
        .from('profiles')
        .select('*')
        .eq('uid', data.user.id)
        .single();

    if (profileError || !profile) {
        // Fallback to metadata if profile table fetch fails
        const meta = data.user.user_metadata;
        return {
            uid: data.user.id,
            email: data.user.email!,
            firstName: meta.first_name || 'User',
            lastName: meta.last_name || '',
            role: meta.role || UserRole.FACULTY,
            department: meta.department
        };
    }

    return {
        uid: profile.uid,
        email: profile.email,
        firstName: profile.first_name,
        lastName: profile.last_name,
        role: profile.role as UserRole,
        department: profile.department
    };
};


