            uid: `mock-${Date.now()}`,
            email,
            firstName: userData.firstName!,
            lastName: userData.lastName!,
            role: userData.role || UserRole.FACULTY,
            department: userData.department
        };
        mockUsersStore.push(newUser);
        return newUser;
    }
};

export const loginUser = async (email: string, password: string): Promise<User> => {
    if (isSupabaseConfigured) {
        const { data, error } = await supabase.auth.signInWithPassword({
            email,
            password
        });

        if (error) throw error;
        if (!data.user) throw new Error("Login failed");

        // Fetch profile details
        const { data: profile, error: profileError } = await supabase
            .from('profiles')
            .select('*')
            .eq('uid', data.user.id)
            .single();

        if (profileError || !profile) {
            // Fallback to metadata
            const meta = data.user.user_metadata;
            return {
                uid: data.user.id,
                email: data.user.email!,
                firstName: meta.first_name || 'User',
                lastName: meta.last_name || '',
                role: meta.role || UserRole.FACULTY,
                department: meta.department
            };
        }

        return {
            uid: profile.uid,
            email: profile.email,
            firstName: profile.first_name,
            lastName: profile.last_name,
            role: profile.role as UserRole,
            department: profile.department
        };
    } else {
        // Mock Fallback
        // Simulate login delay
        await new Promise(r => setTimeout(r, 600));

        // Find user in mock store
        const found = mockUsersStore.find(u => u.email.toLowerCase() === email.toLowerCase());
        if (found) return found;

        // If not found, create a temporary session based on email pattern for demo purposes
        // e.g., admin@... logs in as admin
        let role = UserRole.FACULTY;
        if (email.includes('super')) role = UserRole.SUPER_ADMIN;
        else if (email.includes('admin')) role = UserRole.ADMIN;

        return {
            uid: 'temp-session',
            email,
            firstName: 'Demo',
            lastName: role,
            role,
            department: 'Demo Dept'
        };
    }
};


